/* data+ :: content/quiz2.js — DA0-002 Domain 2 question bank (100 items). */
window.DATAPLUS = window.DATAPLUS || {}; DATAPLUS.questions = DATAPLUS.questions || [];
DATAPLUS.questions.push(
{ id:"D2-001", domain:2, obj:"2.1", diff:"easy", q:"An analyst needs to combine a customers table with an orders table so that every customer appears in the result, even those who have never placed an order. Which join should be used?", options:["INNER JOIN","LEFT OUTER JOIN","CROSS JOIN","Self join"], answer:1, explain:"<strong>LEFT OUTER JOIN</strong> returns every row from the left table (customers) and matching rows from the right table, filling NULLs where no order exists, so customers without orders are still included.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>INNER JOIN</b>: an inner join returns only rows with a match in both tables, so customers with no orders would be dropped.</span><span class='qd'><b>CROSS JOIN</b>: a cross join produces the Cartesian product of every customer paired with every order, which is not the intent.</span><span class='qd'><b>Self join</b>: a self join joins a table to itself and does not combine two different tables.</span>" },
{ id:"D2-002", domain:2, obj:"2.1", diff:"easy", q:"A reporting team wants only the rows that exist in BOTH the active_users table and the licensed_users table, matched on user_id. Which join produces this result?", options:["FULL OUTER JOIN","RIGHT OUTER JOIN","INNER JOIN","UNION ALL"], answer:2, explain:"<strong>INNER JOIN</strong> returns only the rows where the join key matches in both tables, giving exactly the intersection of active and licensed users.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>FULL OUTER JOIN</b>: a full outer join keeps unmatched rows from both sides, returning more than the intersection.</span><span class='qd'><b>RIGHT OUTER JOIN</b>: a right outer join keeps all rows from the right table including those without a match.</span><span class='qd'><b>UNION ALL</b>: UNION ALL stacks rows vertically rather than matching them on a key.</span>" },
{ id:"D2-003", domain:2, obj:"2.1", diff:"medium", q:"An analyst joins a 5,000-row products table to a 200-row categories table but forgets the ON clause, and the query returns 1,000,000 rows. What happened?", options:["A self join collapsed the rows","An accidental CROSS JOIN produced the Cartesian product","A LEFT JOIN duplicated the categories","An INNER JOIN matched every key"], answer:1, explain:"<strong>An accidental CROSS JOIN produced the Cartesian product</strong> — omitting the join condition pairs every product with every category, yielding 5,000 x 200 = 1,000,000 rows.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A self join collapsed the rows</b>: a self join references one table twice and would not multiply two separate tables this way.</span><span class='qd'><b>A LEFT JOIN duplicated the categories</b>: a LEFT JOIN still requires a matching condition and would not blow up to a full Cartesian product.</span><span class='qd'><b>An INNER JOIN matched every key</b>: an inner join needs an ON clause to match keys; without it, no controlled matching occurs.</span>" },
{ id:"D2-004", domain:2, obj:"2.1", diff:"medium", q:"An analyst must build an org chart showing each employee next to their manager, where both employee and manager records live in the same employees table. Which technique is required?", options:["FULL OUTER JOIN","UNION","CROSS JOIN","Self join"], answer:3, explain:"<strong>Self join</strong> joins the employees table to itself, aliasing it twice so each employee row can be matched to its manager's row via the manager_id-to-employee_id relationship.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>FULL OUTER JOIN</b>: a full outer join combines two separate tables and is not how a single table references its own hierarchy.</span><span class='qd'><b>UNION</b>: UNION appends result sets vertically and cannot relate a row to another row in the same table.</span><span class='qd'><b>CROSS JOIN</b>: a cross join pairs every row with every other row with no hierarchy logic, producing meaningless combinations.</span>" },
{ id:"D2-005", domain:2, obj:"2.1", diff:"medium", q:"A data engineer needs a single result that keeps ALL customers and ALL support tickets, including customers with no tickets and orphaned tickets with no matching customer. Which join is appropriate?", options:["INNER JOIN","LEFT OUTER JOIN","FULL OUTER JOIN","RIGHT OUTER JOIN"], answer:2, explain:"<strong>FULL OUTER JOIN</strong> returns all rows from both tables, matching where possible and filling NULLs on either side, so unmatched customers and unmatched tickets are both retained.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>INNER JOIN</b>: an inner join drops every unmatched row, losing both the ticket-less customers and the orphaned tickets.</span><span class='qd'><b>LEFT OUTER JOIN</b>: a left join keeps unmatched customers but discards orphaned tickets that have no customer.</span><span class='qd'><b>RIGHT OUTER JOIN</b>: a right join keeps unmatched tickets but discards customers who have no tickets.</span>" },
{ id:"D2-006", domain:2, obj:"2.1", diff:"medium", q:"An analyst wants to stack last year's sales rows on top of this year's sales rows into one column set, automatically removing any identical duplicate rows that appear in both. Which operator should be used?", options:["UNION ALL","JOIN","UNION","INTERSECT"], answer:2, explain:"<strong>UNION</strong> combines two result sets vertically and removes duplicate rows, returning a distinct set across both years.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>UNION ALL</b>: UNION ALL also stacks the rows but keeps every duplicate rather than removing them.</span><span class='qd'><b>JOIN</b>: a join combines columns side by side on a key, not rows stacked vertically.</span><span class='qd'><b>INTERSECT</b>: INTERSECT returns only rows common to both sets, not the full combined set.</span>" },
{ id:"D2-007", domain:2, obj:"2.1", diff:"easy", q:"Two monthly extract files have identical columns and the analyst wants to combine all rows from both, keeping duplicates for an audit count. Which is the BEST choice?", options:["UNION","INNER JOIN","GROUP BY","UNION ALL"], answer:3, explain:"<strong>UNION ALL</strong> appends all rows from both sets and preserves duplicates, which is required for an accurate audit count and is also faster because it skips the de-duplication step.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>UNION</b>: UNION removes duplicate rows, which would undercount records during an audit.</span><span class='qd'><b>INNER JOIN</b>: a join matches columns on a key rather than appending whole rows from two files.</span><span class='qd'><b>GROUP BY</b>: GROUP BY aggregates rows into groups and does not append two datasets together.</span>" },
{ id:"D2-008", domain:2, obj:"2.1", diff:"medium", q:"A SQL UNION between two SELECT statements returns the error 'each UNION query must have an equal number of columns.' What is the root cause?", options:["The two SELECT lists return a different number of columns","The tables have different row counts","The ORDER BY clause is missing","The join key is not indexed"], answer:0, explain:"<strong>The two SELECT lists return a different number of columns</strong> — UNION requires both queries to project the same number of columns with compatible data types so the rows can be stacked.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The tables have different row counts</b>: UNION combines rows regardless of how many each side has, so differing row counts is not an error.</span><span class='qd'><b>The ORDER BY clause is missing</b>: ORDER BY is optional and its absence does not cause a column-count mismatch.</span><span class='qd'><b>The join key is not indexed</b>: UNION does not use a join key, and indexing affects performance, not column-count validity.</span>" },
{ id:"D2-009", domain:2, obj:"2.1", diff:"easy", q:"An analyst writes 'WHERE region = ''West''' in a query. What is the purpose of this clause?", options:["To filter rows down to only those in the West region","To group rows by region","To sort the output alphabetically","To join the region table"], answer:0, explain:"<strong>To filter rows down to only those in the West region</strong> — the WHERE clause restricts the result set to rows that meet the specified condition.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To group rows by region</b>: grouping is performed by GROUP BY, not WHERE.</span><span class='qd'><b>To sort the output alphabetically</b>: sorting is performed by ORDER BY, not WHERE.</span><span class='qd'><b>To join the region table</b>: joining requires a JOIN clause, which WHERE alone does not provide.</span>" },
{ id:"D2-010", domain:2, obj:"2.1", diff:"medium", q:"An analyst needs the total revenue per product category. Which combination of SQL features accomplishes this?", options:["GROUP BY category with SUM(revenue)","WHERE with ORDER BY","DISTINCT with a self join","UNION ALL with COUNT"], answer:0, explain:"<strong>GROUP BY category with SUM(revenue)</strong> collapses rows into one row per category and applies the SUM aggregate to total the revenue within each group.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>WHERE with ORDER BY</b>: WHERE filters and ORDER BY sorts, but neither aggregates revenue per category.</span><span class='qd'><b>DISTINCT with a self join</b>: DISTINCT removes duplicates and a self join relates a table to itself; neither sums values per group.</span><span class='qd'><b>UNION ALL with COUNT</b>: UNION ALL stacks rows and COUNT tallies records, which does not total a revenue measure by category.</span>" },
{ id:"D2-011", domain:2, obj:"2.1", diff:"hard", q:"An analyst wants only the product categories whose total sales exceed 100,000. The aggregate SUM must be filtered after grouping. Which clause is required?", options:["HAVING SUM(sales) > 100000","WHERE SUM(sales) > 100000","ORDER BY SUM(sales)","DISTINCT SUM(sales)"], answer:0, explain:"<strong>HAVING SUM(sales) > 100000</strong> filters groups after aggregation, which is required because WHERE is evaluated before rows are grouped and cannot reference an aggregate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>WHERE SUM(sales) > 100000</b>: WHERE runs before grouping and cannot reference aggregate functions, so this raises an error.</span><span class='qd'><b>ORDER BY SUM(sales)</b>: ORDER BY only sorts the output and does not remove groups below the threshold.</span><span class='qd'><b>DISTINCT SUM(sales)</b>: DISTINCT removes duplicate values and cannot apply a greater-than filter to groups.</span>" },
{ id:"D2-012", domain:2, obj:"2.1", diff:"medium", q:"An analyst needs the average order value but only for orders placed in 2024, then averaged by salesperson. In which order are WHERE and GROUP BY logically applied?", options:["WHERE filters rows first, then GROUP BY aggregates the remaining rows","GROUP BY is applied first, then WHERE filters the groups","Both are applied simultaneously","ORDER BY must run before WHERE"], answer:0, explain:"<strong>WHERE filters rows first, then GROUP BY aggregates the remaining rows</strong> — the engine restricts to 2024 orders before forming salesperson groups and computing the averages.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>GROUP BY is applied first, then WHERE filters the groups</b>: WHERE cannot filter groups; group-level filtering is HAVING and occurs after grouping.</span><span class='qd'><b>Both are applied simultaneously</b>: SQL has a defined logical processing order; WHERE precedes GROUP BY.</span><span class='qd'><b>ORDER BY must run before WHERE</b>: ORDER BY is one of the last steps, applied after filtering and grouping.</span>" },
{ id:"D2-013", domain:2, obj:"2.1", diff:"easy", q:"Which SQL aggregate function returns the number of rows in a group?", options:["SUM()","MAX()","COUNT()","AVG()"], answer:2, explain:"<strong>COUNT()</strong> returns the number of rows (or non-null values) in a group, making it the right function for tallying records.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SUM()</b>: SUM adds up numeric values rather than counting rows.</span><span class='qd'><b>MAX()</b>: MAX returns the largest value in a column, not a row count.</span><span class='qd'><b>AVG()</b>: AVG computes the mean of a numeric column, not the number of rows.</span>" },
{ id:"D2-014", domain:2, obj:"2.1", diff:"hard", q:"A dashboard query that scans a 50-million-row sales table by customer_id runs slowly. The customer_id column has no index. Which optimization will MOST directly speed up the lookup?", options:["Add SELECT * to return all columns","Replace the WHERE clause with HAVING","Create an index on the customer_id column","Convert the query to UNION ALL"], answer:2, explain:"<strong>Create an index on the customer_id column</strong> lets the engine seek matching rows directly instead of scanning all 50 million rows, dramatically reducing lookup time.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add SELECT * to return all columns</b>: returning more columns increases I/O and makes the query slower, not faster.</span><span class='qd'><b>Replace the WHERE clause with HAVING</b>: HAVING filters after aggregation and would not improve a row-level lookup.</span><span class='qd'><b>Convert the query to UNION ALL</b>: UNION ALL combines result sets and does nothing to accelerate a single filtered scan.</span>" },
{ id:"D2-015", domain:2, obj:"2.1", diff:"medium", q:"A reporting query selects every column with SELECT * but the report only displays three fields. What query optimization should the analyst apply?", options:["Add an ORDER BY clause","Wrap the query in a UNION","Remove the WHERE clause","Select only the three needed columns instead of using SELECT *"], answer:3, explain:"<strong>Select only the three needed columns instead of using SELECT *</strong> reduces the amount of data read and transferred, lowering I/O and improving performance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add an ORDER BY clause</b>: sorting adds work and does not reduce the columns being retrieved.</span><span class='qd'><b>Wrap the query in a UNION</b>: a UNION adds an extra result-set operation and would not narrow the columns.</span><span class='qd'><b>Remove the WHERE clause</b>: removing the filter returns more rows and would slow the query.</span>" },
{ id:"D2-016", domain:2, obj:"2.1", diff:"medium", q:"A complex report repeatedly references the same expensive intermediate result within one batch. Which technique stores that interim result so it can be reused without recomputing it?", options:["Adding a CROSS JOIN","Using SELECT DISTINCT","Creating a temporary table","Increasing the WHERE conditions"], answer:2, explain:"<strong>Creating a temporary table</strong> materializes the expensive interim result once so subsequent steps can reference it, avoiding repeated recomputation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Adding a CROSS JOIN</b>: a cross join multiplies rows and would increase, not reduce, the work performed.</span><span class='qd'><b>Using SELECT DISTINCT</b>: DISTINCT de-duplicates output but does not cache an intermediate result for reuse.</span><span class='qd'><b>Increasing the WHERE conditions</b>: more filters narrow rows but do not store a reusable interim result.</span>" },
{ id:"D2-017", domain:2, obj:"2.1", diff:"medium", q:"A developer runs the same lookup query thousands of times with different ID values and wants the database to reuse a single compiled execution plan. Which approach achieves this?", options:["String-concatenating each ID into the SQL text","Adding SELECT * to each call","Disabling all indexes","Using a parameterized query with bind variables"], answer:3, explain:"<strong>Using a parameterized query with bind variables</strong> lets the database compile the plan once and reuse it for every value, improving performance and preventing SQL injection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>String-concatenating each ID into the SQL text</b>: building unique SQL strings forces a new plan compile each time and opens an injection risk.</span><span class='qd'><b>Adding SELECT * to each call</b>: returning all columns increases load and does nothing for plan reuse.</span><span class='qd'><b>Disabling all indexes</b>: removing indexes slows lookups and is unrelated to plan caching.</span>" },
{ id:"D2-018", domain:2, obj:"2.1", diff:"easy", q:"In an ETL pipeline, in what order do the three stages occur?", options:["Transform, Extract, Load","Load, Extract, Transform","Extract, Transform, Load","Extract, Load, Transform"], answer:2, explain:"<strong>Extract, Transform, Load</strong> — ETL pulls data from sources, cleans and reshapes it in a staging area, then loads the finished data into the target.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Transform, Extract, Load</b>: you cannot transform data before it has been extracted from the source.</span><span class='qd'><b>Load, Extract, Transform</b>: loading must come after extraction and transformation, not first.</span><span class='qd'><b>Extract, Load, Transform</b>: this describes ELT, a different pattern where transformation happens after loading.</span>" },
{ id:"D2-019", domain:2, obj:"2.1", diff:"hard", q:"A team loads raw data straight into a cloud data warehouse and uses the warehouse's compute to transform it afterward. Which pattern are they using and why is it suited to the cloud?", options:["ETL, because transformation must happen before loading","ETL, because cloud storage is cheaper than compute","ELT, because powerful warehouse compute can transform data after it is loaded","ELT, because data cannot be transformed in the cloud"], answer:2, explain:"<strong>ELT, because powerful warehouse compute can transform data after it is loaded</strong> — modern cloud warehouses scale compute to transform large raw datasets in place, making load-first efficient.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ETL, because transformation must happen before loading</b>: the scenario explicitly transforms after loading, which is ELT, not ETL.</span><span class='qd'><b>ETL, because cloud storage is cheaper than compute</b>: this mislabels the pattern and the rationale does not match load-then-transform.</span><span class='qd'><b>ELT, because data cannot be transformed in the cloud</b>: cloud platforms absolutely can transform data; this rationale is false.</span>" },
{ id:"D2-020", domain:2, obj:"2.1", diff:"medium", q:"During the Transform stage of ETL, which of the following activities is MOST representative of that stage?", options:["Connecting to the source API to pull rows","Standardizing date formats and removing duplicates","Inserting finished rows into the warehouse table","Scheduling the nightly pipeline run"], answer:1, explain:"<strong>Standardizing date formats and removing duplicates</strong> are transformation activities that clean and conform the data before it is loaded.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Connecting to the source API to pull rows</b>: connecting to and pulling from a source is the Extract stage.</span><span class='qd'><b>Inserting finished rows into the warehouse table</b>: inserting into the target is the Load stage.</span><span class='qd'><b>Scheduling the nightly pipeline run</b>: scheduling is orchestration and not part of transforming the data itself.</span>" },
{ id:"D2-021", domain:2, obj:"2.1", diff:"easy", q:"A researcher surveys every 10th customer from an ordered list of all customers to estimate satisfaction. Which sampling method is this?", options:["Systematic sampling","Simple random sampling","Stratified sampling","Convenience sampling"], answer:0, explain:"<strong>Systematic sampling</strong> selects every nth element from an ordered list using a fixed interval, exactly as choosing every 10th customer does.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Simple random sampling</b>: simple random sampling gives every member an equal independent chance, not a fixed-interval selection.</span><span class='qd'><b>Stratified sampling</b>: stratified sampling divides the population into subgroups and samples within each, which is not described here.</span><span class='qd'><b>Convenience sampling</b>: convenience sampling picks whoever is easiest to reach rather than following a defined interval.</span>" },
{ id:"D2-022", domain:2, obj:"2.1", diff:"hard", q:"A polling firm must ensure its sample reflects the population's age brackets in the same proportions as the overall population. Which sampling method achieves this representativeness?", options:["Convenience sampling","Systematic sampling","Stratified sampling","Snowball sampling"], answer:2, explain:"<strong>Stratified sampling</strong> divides the population into strata such as age brackets and samples proportionally from each, preserving the population's proportions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Convenience sampling</b>: convenience sampling uses easily available subjects and offers no proportional control across age groups.</span><span class='qd'><b>Systematic sampling</b>: systematic sampling uses a fixed interval and does not guarantee each age bracket is proportionally represented.</span><span class='qd'><b>Snowball sampling</b>: snowball sampling recruits via referrals and can badly skew representativeness.</span>" },
{ id:"D2-023", domain:2, obj:"2.1", diff:"medium", q:"An online survey collects responses only from visitors who happen to be on the company website that day. Which problem does this introduce?", options:["The sample is a true random sample","Perfect population coverage","Stratification of all subgroups","Selection bias from convenience sampling"], answer:3, explain:"<strong>Selection bias from convenience sampling</strong> arises because only easily reachable site visitors respond, so the sample may not represent the broader customer base.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The sample is a true random sample</b>: respondents self-select by visiting, so it is not a random sample.</span><span class='qd'><b>Perfect population coverage</b>: only that day's visitors are reachable, leaving most of the population uncovered.</span><span class='qd'><b>Stratification of all subgroups</b>: no subgroups are defined or proportionally sampled here.</span>" },
{ id:"D2-024", domain:2, obj:"2.1", diff:"easy", q:"What is the primary goal of data integration in a data acquisition workflow?", options:["To delete redundant tables","To combine data from multiple sources into a unified, consistent view","To encrypt data at rest","To visualize data in a dashboard"], answer:1, explain:"<strong>To combine data from multiple sources into a unified, consistent view</strong> is the core purpose of data integration, enabling analysis across previously separate systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To delete redundant tables</b>: removing redundancy is a cleansing task, not the defining goal of integration.</span><span class='qd'><b>To encrypt data at rest</b>: encryption is a security control, unrelated to merging sources.</span><span class='qd'><b>To visualize data in a dashboard</b>: visualization is a downstream reporting step, not integration itself.</span>" },
{ id:"D2-025", domain:2, obj:"2.1", diff:"medium", q:"A survey question asks 'Don't you agree that our excellent service was outstanding?' What flaw does this introduce into the collected data?", options:["Sampling interval error","A leading question that biases responses","Insufficient sample size","A stratification error"], answer:1, explain:"<strong>A leading question that biases responses</strong> — the wording pushes respondents toward agreement, distorting the data away from their true opinions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Sampling interval error</b>: interval errors concern how subjects are selected, not how a question is worded.</span><span class='qd'><b>Insufficient sample size</b>: sample size relates to how many respondents there are, not the bias in a single question.</span><span class='qd'><b>A stratification error</b>: stratification concerns dividing the population into subgroups, not question phrasing.</span>" },
{ id:"D2-026", domain:2, obj:"2.1", diff:"medium", q:"An analyst writes a nested subquery in the FROM clause that the optimizer can fold into the outer query, but a correlated subquery in the SELECT runs once per outer row and is slow. What is the BEST optimization?", options:["Add SELECT * to the subquery","Rewrite the correlated subquery as a join","Convert the query to a CROSS JOIN","Remove all WHERE filters"], answer:1, explain:"<strong>Rewrite the correlated subquery as a join</strong> lets the engine evaluate the relationship in a single set-based operation instead of executing the subquery repeatedly for every outer row.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add SELECT * to the subquery</b>: returning more columns increases work and does not eliminate the per-row execution.</span><span class='qd'><b>Convert the query to a CROSS JOIN</b>: a cross join multiplies rows and would worsen performance.</span><span class='qd'><b>Remove all WHERE filters</b>: removing filters returns more rows and slows the query further.</span>" },
{ id:"D2-027", domain:2, obj:"2.1", diff:"easy", q:"An ETL job must pull only records changed since the last run rather than reloading the entire source each night. Which extraction approach is this?", options:["Full extraction","Cartesian extraction","Random extraction","Incremental (delta) extraction"], answer:3, explain:"<strong>Incremental (delta) extraction</strong> pulls only the records added or changed since the last load, reducing volume and runtime compared with reloading everything.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full extraction</b>: a full extraction reloads the entire source each time, which is what the team is trying to avoid.</span><span class='qd'><b>Cartesian extraction</b>: there is no such extraction method; Cartesian refers to a cross join of rows.</span><span class='qd'><b>Random extraction</b>: pulling random records would miss many changes and is not a defined incremental method.</span>" },
{ id:"D2-028", domain:2, obj:"2.1", diff:"easy", q:"An analyst combines two tables side by side, matching rows on a shared key column. This operation is generally called a:", options:["Union","Filter","Join","Aggregation"], answer:2, explain:"<strong>Join</strong> combines columns from two tables horizontally by matching rows on a shared key, producing a wider result set.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Union</b>: a union stacks rows vertically rather than matching them side by side on a key.</span><span class='qd'><b>Filter</b>: filtering restricts which rows are returned and does not combine two tables.</span><span class='qd'><b>Aggregation</b>: aggregation summarizes values into groups and does not merge two tables on a key.</span>" },
{ id:"D2-029", domain:2, obj:"2.1", diff:"medium", q:"A query joins orders to customers and the analyst wants results sorted from highest to lowest order amount. Which clause and keyword produce this?", options:["GROUP BY amount ASC","HAVING amount DESC","ORDER BY amount DESC","WHERE amount > 0"], answer:2, explain:"<strong>ORDER BY amount DESC</strong> sorts the result set by the order amount in descending order, placing the highest amounts first.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>GROUP BY amount ASC</b>: GROUP BY aggregates rows and does not take an ASC/DESC sort direction by itself.</span><span class='qd'><b>HAVING amount DESC</b>: HAVING filters groups and cannot specify sort order.</span><span class='qd'><b>WHERE amount > 0</b>: WHERE filters rows and does not sort them.</span>" },
{ id:"D2-030", domain:2, obj:"2.1", diff:"medium", q:"A company integrates a CRM, an ERP, and a marketing platform whose customer_id formats differ. Before joining, what must happen for the join keys to match correctly?", options:["Encrypt all three sources","Delete the smaller two sources","Convert the join to a UNION","Standardize and map the customer_id values to a common format"], answer:3, explain:"<strong>Standardize and map the customer_id values to a common format</strong> ensures the keys align so the join matches the same customer across systems instead of failing or mismatching.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypt all three sources</b>: encryption protects data but does nothing to reconcile differing key formats.</span><span class='qd'><b>Delete the smaller two sources</b>: deleting sources discards data the integration needs.</span><span class='qd'><b>Convert the join to a UNION</b>: a UNION stacks rows and would not match the same customer across systems.</span>" },
{ id:"D2-031", domain:2, obj:"2.2", diff:"easy", q:"While profiling a dataset, an analyst finds blank cells in the email column. These blanks are an example of:", options:["Outliers","Missing values","Duplicates","Derived fields"], answer:1, explain:"<strong>Missing values</strong> are absent or blank entries where a value was expected, such as empty cells in the email column.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Outliers</b>: outliers are extreme values that are present, not absent.</span><span class='qd'><b>Duplicates</b>: duplicates are repeated records, the opposite of missing data.</span><span class='qd'><b>Derived fields</b>: derived fields are calculated from other columns and are not blank source values.</span>" },
{ id:"D2-032", domain:2, obj:"2.2", diff:"medium", q:"An analyst notices a 'units_sold' column stores 0 for days with no sales and NULL for days the store was closed. Why is preserving this distinction important during exploration?", options:["NULL and 0 are always interchangeable","0 is a real measured value while NULL means data is absent or not applicable","NULL should always be replaced with 0","0 indicates a duplicate row"], answer:1, explain:"<strong>0 is a real measured value while NULL means data is absent or not applicable</strong> — conflating them would misstate averages and counts, so the distinction must be preserved.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>NULL and 0 are always interchangeable</b>: treating them the same corrupts aggregates because zero is a measurement and NULL is the absence of one.</span><span class='qd'><b>NULL should always be replaced with 0</b>: blindly replacing NULL with 0 invents data for closed days and skews results.</span><span class='qd'><b>0 indicates a duplicate row</b>: a zero value has nothing to do with row duplication.</span>" },
{ id:"D2-033", domain:2, obj:"2.2", diff:"hard", q:"An analyst finds that survey respondents with the highest incomes most often left the income field blank. This non-random pattern of missingness is BEST described as:", options:["Missing not at random (MNAR)","Missing completely at random (MCAR)","A duplicate record","An outlier"], answer:0, explain:"<strong>Missing not at random (MNAR)</strong> occurs when the probability of a value being missing depends on the unobserved value itself, as high earners selectively skip the income question.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Missing completely at random (MCAR)</b>: MCAR means missingness is unrelated to any value, but here it depends on income level.</span><span class='qd'><b>A duplicate record</b>: a blank field is missing data, not a repeated record.</span><span class='qd'><b>An outlier</b>: an outlier is an extreme present value, not an absent one.</span>" },
{ id:"D2-034", domain:2, obj:"2.2", diff:"medium", q:"A customer table has two rows for 'John Smith' with the same email, phone, and address. What data quality issue is this?", options:["A missing value","Duplication","An outlier","A type mismatch"], answer:1, explain:"<strong>Duplication</strong> describes the same real-world entity represented by more than one record, as with the two identical John Smith rows.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A missing value</b>: the rows are fully populated, so nothing is missing.</span><span class='qd'><b>An outlier</b>: an outlier is an extreme value, not a repeated record.</span><span class='qd'><b>A type mismatch</b>: a type mismatch is a wrong data type, which is not described here.</span>" },
{ id:"D2-035", domain:2, obj:"2.2", diff:"hard", q:"A data warehouse stores a customer's full mailing address in both the customers table and the orders table, and the two copies sometimes disagree. This storage of the same fact in multiple places is BEST described as:", options:["Data redundancy","An outlier","A missing value","A leading question"], answer:0, explain:"<strong>Data redundancy</strong> is the unnecessary repetition of the same fact across locations, which risks inconsistency when copies fall out of sync.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An outlier</b>: an outlier is an extreme value, not duplicated storage of a fact.</span><span class='qd'><b>A missing value</b>: the address is present in both places, so nothing is missing.</span><span class='qd'><b>A leading question</b>: a leading question is a survey-design flaw unrelated to redundant storage.</span>" },
{ id:"D2-036", domain:2, obj:"2.2", diff:"easy", q:"In a column of customer ages ranging mostly from 18 to 75, one record shows an age of 250. This single extreme value is called a(n):", options:["Duplicate","Outlier","Null","Foreign key"], answer:1, explain:"<strong>Outlier</strong> describes a value that lies far outside the typical range, such as an age of 250 among values of 18 to 75.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Duplicate</b>: a duplicate is a repeated record, not a single extreme value.</span><span class='qd'><b>Null</b>: a null is a missing value, but 250 is present.</span><span class='qd'><b>Foreign key</b>: a foreign key is a referential column, not an extreme data point.</span>" },
{ id:"D2-037", domain:2, obj:"2.2", diff:"medium", q:"An analyst flags values that fall below Q1 minus 1.5 times the IQR or above Q3 plus 1.5 times the IQR. Which technique is being used to detect anomalies?", options:["Z-score normalization","One-hot encoding","Min-max scaling","The interquartile range (IQR) method"], answer:3, explain:"<strong>The interquartile range (IQR) method</strong> identifies outliers as points beyond 1.5 times the IQR below Q1 or above Q3, a standard distribution-free detection rule.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Z-score normalization</b>: z-scores measure standard deviations from the mean; this rule uses quartiles, not the mean and standard deviation.</span><span class='qd'><b>One-hot encoding</b>: one-hot encoding converts categories to binary columns and does not detect outliers.</span><span class='qd'><b>Min-max scaling</b>: min-max scaling rescales values to a range and is not an outlier-detection rule.</span>" },
{ id:"D2-038", domain:2, obj:"2.2", diff:"medium", q:"An analyst finds an order with a delivery_date that is earlier than its order_date. This is an example of which data quality problem?", options:["An invalid value caught by a logical/business-rule check","A duplicate row","A perfectly valid record","A missing foreign key"], answer:0, explain:"<strong>An invalid value caught by a logical/business-rule check</strong> — a delivery date preceding the order date violates a business rule, flagging the record as invalid.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A duplicate row</b>: the issue is an impossible date relationship, not a repeated record.</span><span class='qd'><b>A perfectly valid record</b>: a delivery before the order is logically impossible, so the record is not valid.</span><span class='qd'><b>A missing foreign key</b>: both dates are present; nothing references a missing key.</span>" },
{ id:"D2-039", domain:2, obj:"2.2", diff:"medium", q:"A dataset of 10,000 sales should have a non-null product_id on every row, but 400 rows have it blank. The analyst reports 96% non-null. Which data quality dimension is being measured?", options:["Completeness","Timeliness","Uniqueness","Confidentiality"], answer:0, explain:"<strong>Completeness</strong> measures the proportion of required values that are actually present, here 9,600 of 10,000 rows or 96%.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Timeliness</b>: timeliness concerns how current the data is, not whether values are present.</span><span class='qd'><b>Uniqueness</b>: uniqueness concerns the absence of duplicates, not blank fields.</span><span class='qd'><b>Confidentiality</b>: confidentiality is a security property, not a data quality measure of presence.</span>" },
{ id:"D2-040", domain:2, obj:"2.2", diff:"easy", q:"Before loading a file, an analyst checks that every email address contains an '@' symbol and a domain. This step is an example of:", options:["Data visualization","Data encryption","Data sampling","Data validation"], answer:3, explain:"<strong>Data validation</strong> verifies that values conform to expected rules or formats, such as confirming each email contains an '@' and a domain.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data visualization</b>: visualization presents data graphically and does not check format rules.</span><span class='qd'><b>Data encryption</b>: encryption secures data and does not verify formatting.</span><span class='qd'><b>Data sampling</b>: sampling selects a subset of records and does not validate format.</span>" },
{ id:"D2-041", domain:2, obj:"2.2", diff:"hard", q:"An analyst must decide whether an extreme sensor reading is a genuine event or a recording error before removing it. What is the BEST first action?", options:["Investigate the value against context and source before deciding to keep, correct, or remove it","Immediately delete the value as an outlier","Replace it with the column mean automatically","Duplicate the row to preserve it"], answer:0, explain:"<strong>Investigate the value against context and source before deciding to keep, correct, or remove it</strong> — outliers can be real signals, so analysts must determine the cause before acting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Immediately delete the value as an outlier</b>: deleting before investigation can discard a legitimate, meaningful event.</span><span class='qd'><b>Replace it with the column mean automatically</b>: imputing without understanding the cause may mask a real anomaly or error.</span><span class='qd'><b>Duplicate the row to preserve it</b>: duplicating adds redundancy and does nothing to determine validity.</span>" },
{ id:"D2-042", domain:2, obj:"2.2", diff:"medium", q:"During deduplication, two records refer to the same customer but one spells the city 'NYC' and the other 'New York'. Which technique helps identify them as the same entity?", options:["Exact-match deduplication only","Fuzzy matching on standardized fields","Increasing the sample size","Adding a CROSS JOIN"], answer:1, explain:"<strong>Fuzzy matching on standardized fields</strong> compares records by similarity rather than exact equality, recognizing variants like 'NYC' and 'New York' as the same entity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Exact-match deduplication only</b>: exact matching would treat the two spellings as different and miss the duplicate.</span><span class='qd'><b>Increasing the sample size</b>: more data does not help match two specific variant records.</span><span class='qd'><b>Adding a CROSS JOIN</b>: a cross join multiplies rows and does not identify duplicates.</span>" },
{ id:"D2-043", domain:2, obj:"2.2", diff:"medium", q:"A profiling report shows a phone column where 30% of values are letters instead of digits. Which data quality dimension is failing?", options:["Timeliness","Availability","Validity (conformance to format rules)","Non-repudiation"], answer:2, explain:"<strong>Validity (conformance to format rules)</strong> is failing because phone numbers should contain digits, and letters violate the expected format.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Timeliness</b>: timeliness measures how current data is, not whether it matches a format.</span><span class='qd'><b>Availability</b>: availability is a security property about access, not formatting correctness.</span><span class='qd'><b>Non-repudiation</b>: non-repudiation concerns proving who performed an action, unrelated to phone format.</span>" },
{ id:"D2-044", domain:2, obj:"2.2", diff:"easy", q:"What does data profiling primarily accomplish during the exploration phase?", options:["Encrypts the dataset","Builds the final dashboard","Schedules the ETL job","Examines structure, content, and quality to reveal inconsistencies"], answer:3, explain:"<strong>Examines structure, content, and quality to reveal inconsistencies</strong> defines data profiling, which surfaces nulls, outliers, duplicates, and format issues early.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypts the dataset</b>: encryption is a security control, not a profiling activity.</span><span class='qd'><b>Builds the final dashboard</b>: dashboard building is a reporting task, not exploration.</span><span class='qd'><b>Schedules the ETL job</b>: scheduling is orchestration, not data profiling.</span>" },
{ id:"D2-045", domain:2, obj:"2.2", diff:"medium", q:"An analyst joins two tables and the row count unexpectedly triples. Investigation shows the join key has duplicate values in one table. What is the MOST likely explanation?", options:["A missing value in the key","A fan-out caused by duplicate keys producing many-to-many matches","An outlier in a numeric column","A leading survey question"], answer:1, explain:"<strong>A fan-out caused by duplicate keys producing many-to-many matches</strong> — when the join key repeats, each row matches multiple rows, multiplying the result count.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A missing value in the key</b>: missing keys would reduce matches, not multiply rows.</span><span class='qd'><b>An outlier in a numeric column</b>: an extreme numeric value does not affect how a join matches keys.</span><span class='qd'><b>A leading survey question</b>: survey wording has nothing to do with join cardinality.</span>" },
{ id:"D2-046", domain:2, obj:"2.2", diff:"easy", q:"An analyst wants to confirm a numeric 'discount_pct' column only contains values between 0 and 100. Which validation check is MOST appropriate?", options:["A spelling check","A range check","A duplicate count","A cross join"], answer:1, explain:"<strong>A range check</strong> verifies that values fall within an allowed minimum and maximum, ideal for confirming discount percentages stay between 0 and 100.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A spelling check</b>: spelling checks apply to text, not numeric ranges.</span><span class='qd'><b>A duplicate count</b>: counting duplicates does not verify that values fall in a range.</span><span class='qd'><b>A cross join</b>: a cross join combines rows and is unrelated to validating a numeric range.</span>" },
{ id:"D2-047", domain:2, obj:"2.2", diff:"medium", q:"Two systems each define 'active customer' differently, so the same customers are counted twice in a combined report. This is an example of:", options:["A missing value","Redundancy from inconsistent definitions","A type conversion","Min-max scaling"], answer:1, explain:"<strong>Redundancy from inconsistent definitions</strong> — overlapping but differing business definitions cause the same entities to be represented multiple times, inflating counts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A missing value</b>: the problem is duplicate representation, not absent data.</span><span class='qd'><b>A type conversion</b>: type conversion changes data types and is unrelated to duplicate counting.</span><span class='qd'><b>Min-max scaling</b>: min-max scaling rescales numbers and has nothing to do with definition conflicts.</span>" },
{ id:"D2-048", domain:2, obj:"2.2", diff:"hard", q:"A nightly feed is supposed to deliver 24 hourly files, but only 22 arrive. An automated check compares expected versus received counts and raises an alert. Which validation concept does this represent?", options:["One-hot encoding","Min-max scaling","String concatenation","Reconciliation/completeness check"], answer:3, explain:"<strong>Reconciliation/completeness check</strong> compares the expected record or file counts against what was actually received to confirm nothing is missing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>One-hot encoding</b>: one-hot encoding transforms categorical data and does not verify file counts.</span><span class='qd'><b>Min-max scaling</b>: min-max scaling rescales numeric values and is unrelated to load completeness.</span><span class='qd'><b>String concatenation</b>: concatenation joins text and does nothing to reconcile counts.</span>" },
{ id:"D2-049", domain:2, obj:"2.2", diff:"easy", q:"An analyst sorts a numeric column and scans the top and bottom values to spot anything implausible. This quick exploration step primarily helps detect:", options:["Encryption keys","Outliers and invalid extremes","Network latency","Foreign key constraints"], answer:1, explain:"<strong>Outliers and invalid extremes</strong> are revealed by inspecting the largest and smallest values, a fast way to catch impossible or anomalous entries.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encryption keys</b>: scanning sorted values has nothing to do with cryptographic keys.</span><span class='qd'><b>Network latency</b>: latency is an infrastructure metric, not something found by sorting a column.</span><span class='qd'><b>Foreign key constraints</b>: constraints are schema rules, not values revealed by sorting.</span>" },
{ id:"D2-050", domain:2, obj:"2.2", diff:"medium", q:"An analyst discovers that a 'state' column contains both 'CA' and 'California' for the same state. Before this can be fixed, what kind of inconsistency has exploration identified?", options:["A missing primary key","An arithmetic overflow","A representational/standardization inconsistency","A network timeout"], answer:2, explain:"<strong>A representational/standardization inconsistency</strong> — the same value is recorded in different formats, which exploration flags so it can later be standardized.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A missing primary key</b>: both rows have data; nothing about a key is absent here.</span><span class='qd'><b>An arithmetic overflow</b>: overflow is a numeric storage error, not a text-format inconsistency.</span><span class='qd'><b>A network timeout</b>: a timeout is a connectivity issue, unrelated to value representation.</span>" },
{ id:"D2-051", domain:2, obj:"2.3", diff:"easy", q:"An analyst converts the string '1,250.00' stored as text into a number so it can be summed. This operation is called:", options:["Type conversion (casting)","Concatenation","Binning","Deduplication"], answer:0, explain:"<strong>Type conversion (casting)</strong> changes a value from one data type to another, here converting a text string into a numeric value for calculation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Concatenation</b>: concatenation joins strings together rather than changing a data type.</span><span class='qd'><b>Binning</b>: binning groups continuous values into ranges, not converting text to numbers.</span><span class='qd'><b>Deduplication</b>: deduplication removes repeated records and does not change types.</span>" },
{ id:"D2-052", domain:2, obj:"2.3", diff:"medium", q:"An analyst needs to extract the area code (first three digits) from a 10-digit phone string. Which string function is MOST appropriate?", options:["A substring/LEFT function","SUM","ROUND","COUNT"], answer:0, explain:"<strong>A substring/LEFT function</strong> extracts a fixed portion of a string by position, perfect for pulling the first three digits as the area code.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SUM</b>: SUM adds numeric values and cannot extract characters from a string.</span><span class='qd'><b>ROUND</b>: ROUND adjusts numeric precision and does not operate on text positions.</span><span class='qd'><b>COUNT</b>: COUNT tallies rows and cannot pull a substring.</span>" },
{ id:"D2-053", domain:2, obj:"2.3", diff:"hard", q:"An analyst must validate that entries in an 'email' column match the pattern of a valid email address. Which tool is BEST suited to this pattern matching?", options:["A regular expression (regex)","A LEFT JOIN","A pivot table","Min-max scaling"], answer:0, explain:"<strong>A regular expression (regex)</strong> defines a search pattern that can test whether each string matches the structure of an email address.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A LEFT JOIN</b>: a join combines tables and cannot test a string against a pattern.</span><span class='qd'><b>A pivot table</b>: a pivot table summarizes data and does not perform pattern matching.</span><span class='qd'><b>Min-max scaling</b>: scaling rescales numbers and has no role in matching text patterns.</span>" },
{ id:"D2-054", domain:2, obj:"2.3", diff:"medium", q:"A 'full_name' column holds values like 'Smith, John'. The analyst needs separate first and last name columns. Which transformation is required?", options:["Imputation of the mean","Binning into ranges","Z-score normalization","Parsing/splitting the string on the delimiter"], answer:3, explain:"<strong>Parsing/splitting the string on the delimiter</strong> divides the combined value at the comma into separate first-name and last-name fields.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Imputation of the mean</b>: imputation fills missing numeric values and cannot split a text field.</span><span class='qd'><b>Binning into ranges</b>: binning groups continuous numbers into buckets, not split names.</span><span class='qd'><b>Z-score normalization</b>: z-scores standardize numeric data and do not parse strings.</span>" },
{ id:"D2-055", domain:2, obj:"2.3", diff:"hard", q:"A model requires all numeric features rescaled to a 0-to-1 range. The analyst applies (x - min) / (max - min) to each value. Which transformation is this?", options:["Z-score standardization","Binning","One-hot encoding","Min-max scaling (normalization)"], answer:3, explain:"<strong>Min-max scaling (normalization)</strong> rescales values to a fixed range, typically 0 to 1, using the (x - min) / (max - min) formula.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Z-score standardization</b>: z-scores center data on the mean with unit standard deviation, not a fixed 0-to-1 range.</span><span class='qd'><b>Binning</b>: binning buckets continuous values into categories rather than rescaling them.</span><span class='qd'><b>One-hot encoding</b>: one-hot encoding converts categories to binary columns, not numeric rescaling.</span>" },
{ id:"D2-056", domain:2, obj:"2.3", diff:"hard", q:"An analyst transforms a feature by subtracting the mean and dividing by the standard deviation so values are centered at 0 with unit variance. This is:", options:["Min-max scaling","Z-score standardization","Binning","Imputation"], answer:1, explain:"<strong>Z-score standardization</strong> subtracts the mean and divides by the standard deviation, producing values centered at 0 with a standard deviation of 1.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Min-max scaling</b>: min-max scaling maps values to a fixed range using min and max, not the mean and standard deviation.</span><span class='qd'><b>Binning</b>: binning groups values into discrete buckets rather than standardizing them.</span><span class='qd'><b>Imputation</b>: imputation fills in missing values and does not rescale present ones.</span>" },
{ id:"D2-057", domain:2, obj:"2.3", diff:"easy", q:"An analyst groups continuous customer ages into the buckets 0-17, 18-34, 35-54, and 55+. This transformation is called:", options:["Binning","Concatenation","Imputation","Deduplication"], answer:0, explain:"<strong>Binning</strong> converts a continuous variable into discrete categorical ranges, such as grouping ages into defined brackets.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Concatenation</b>: concatenation joins strings and does not create numeric ranges.</span><span class='qd'><b>Imputation</b>: imputation fills missing values rather than grouping present ones.</span><span class='qd'><b>Deduplication</b>: deduplication removes duplicates and does not bucket values.</span>" },
{ id:"D2-058", domain:2, obj:"2.3", diff:"medium", q:"A 'price' column has 50 missing values. The analyst fills each blank with the column's average price. Which technique is this?", options:["Listwise deletion","Binning","Mean imputation","Parsing"], answer:2, explain:"<strong>Mean imputation</strong> replaces missing numeric values with the column's average, a simple way to retain rows while filling gaps.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Listwise deletion</b>: listwise deletion removes rows with missing values rather than filling them.</span><span class='qd'><b>Binning</b>: binning groups values into ranges and does not fill blanks.</span><span class='qd'><b>Parsing</b>: parsing splits strings and is unrelated to filling missing numbers.</span>" },
{ id:"D2-059", domain:2, obj:"2.3", diff:"hard", q:"A dataset of 100,000 rows has 12 rows with a missing optional comment field. The analyst removes only those 12 rows. Which approach is this, and why is it acceptable here?", options:["Mean imputation, because comments are numeric","Min-max scaling, because the field is text","Listwise deletion, because the loss is negligible relative to the dataset","One-hot encoding, because comments are categories"], answer:2, explain:"<strong>Listwise deletion, because the loss is negligible relative to the dataset</strong> — dropping 12 of 100,000 rows removes a trivial fraction and avoids fabricating comment text.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Mean imputation, because comments are numeric</b>: comments are text, so a numeric mean cannot be computed or imputed.</span><span class='qd'><b>Min-max scaling, because the field is text</b>: scaling applies to numbers, and the rationale even contradicts itself.</span><span class='qd'><b>One-hot encoding, because comments are categories</b>: free-text comments are not a small fixed category set suitable for one-hot encoding.</span>" },
{ id:"D2-060", domain:2, obj:"2.3", diff:"medium", q:"An analyst combines a 'first_name' and 'last_name' column into a single 'full_name' column. Which string operation accomplishes this?", options:["Splitting","Binning","Casting","Concatenation"], answer:3, explain:"<strong>Concatenation</strong> joins two or more strings end to end, here combining first and last names into a single full-name field.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Splitting</b>: splitting divides one string into parts, the opposite of combining them.</span><span class='qd'><b>Binning</b>: binning groups numeric values into ranges and does not join text.</span><span class='qd'><b>Casting</b>: casting changes a data type rather than joining strings.</span>" },
{ id:"D2-061", domain:2, obj:"2.3", diff:"medium", q:"A column stores dates as text in mixed formats: 'Jan 5, 2024', '01/05/2024', and '2024-01-05'. To enable date math, what is the BEST transformation?", options:["Parse and convert all entries to a single standardized date data type","Concatenate all three into one string","Bin the dates into months immediately","Delete every row with a date"], answer:0, explain:"<strong>Parse and convert all entries to a single standardized date data type</strong> normalizes the mixed text formats into true dates so calculations like differences and sorting work correctly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Concatenate all three into one string</b>: concatenation only lengthens the text and still leaves the values as unusable strings.</span><span class='qd'><b>Bin the dates into months immediately</b>: binning before standardizing inconsistent formats would mis-bucket many values.</span><span class='qd'><b>Delete every row with a date</b>: deleting all dated rows discards the very data the analysis needs.</span>" },
{ id:"D2-062", domain:2, obj:"2.3", diff:"medium", q:"An analyst trims leading and trailing spaces from a 'city' column so ' Boston ' becomes 'Boston'. Which function performs this cleansing?", options:["SUM","ROUND","TRIM","JOIN"], answer:2, explain:"<strong>TRIM</strong> removes leading and trailing whitespace from a string, cleaning ' Boston ' to 'Boston'.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SUM</b>: SUM adds numbers and cannot remove spaces from text.</span><span class='qd'><b>ROUND</b>: ROUND adjusts numeric precision and does not operate on strings.</span><span class='qd'><b>JOIN</b>: JOIN combines tables and does not trim whitespace.</span>" },
{ id:"D2-063", domain:2, obj:"2.3", diff:"medium", q:"A sales table needs a new 'profit' column equal to revenue minus cost. This new column computed from existing columns is called a:", options:["Derived/calculated field","Primary key","Foreign key","Surrogate key"], answer:0, explain:"<strong>Derived/calculated field</strong> is a column whose values are computed from other columns, such as profit calculated as revenue minus cost.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Primary key</b>: a primary key uniquely identifies rows and is not a computed measure.</span><span class='qd'><b>Foreign key</b>: a foreign key references another table and is not a calculated value.</span><span class='qd'><b>Surrogate key</b>: a surrogate key is an artificial identifier, not a value derived from other columns.</span>" },
{ id:"D2-064", domain:2, obj:"2.3", diff:"easy", q:"An analyst standardizes a 'country' column so 'usa', 'USA', and 'Usa' all become 'USA'. Converting all values to uppercase is an example of:", options:["Imputation","Binning","Sampling","String standardization"], answer:3, explain:"<strong>String standardization</strong> enforces a consistent format such as a single casing, so all country variants become 'USA'.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Imputation</b>: imputation fills missing values and does not normalize casing.</span><span class='qd'><b>Binning</b>: binning groups numbers into ranges, not text into a uniform format.</span><span class='qd'><b>Sampling</b>: sampling selects a subset of rows and does not standardize values.</span>" },
{ id:"D2-065", domain:2, obj:"2.3", diff:"hard", q:"A categorical 'payment_method' column with values cash, card, and crypto must feed a regression model that needs numeric input without implying order. Which transformation is appropriate?", options:["Label-encode as 1, 2, 3","Min-max scaling the text","One-hot encoding into separate binary columns","Z-score standardization"], answer:2, explain:"<strong>One-hot encoding into separate binary columns</strong> represents each category as its own 0/1 column, supplying numeric input without implying a false rank order.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Label-encode as 1, 2, 3</b>: assigning ordinal integers implies a nonexistent ranking among unordered payment methods.</span><span class='qd'><b>Min-max scaling the text</b>: scaling requires numeric input and cannot be applied to category labels.</span><span class='qd'><b>Z-score standardization</b>: z-scores also require numbers and cannot encode nominal categories.</span>" },
{ id:"D2-066", domain:2, obj:"2.3", diff:"easy", q:"An analyst stacks January, February, and March files that share identical columns into one master table, adding the rows together. This row-wise combination is called:", options:["Joining on a key","Pivoting","Appending","Filtering"], answer:2, explain:"<strong>Appending</strong> adds the rows of one dataset beneath another with matching columns, combining the monthly files into one table.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Joining on a key</b>: joining combines columns side by side on a key rather than stacking rows.</span><span class='qd'><b>Pivoting</b>: pivoting reshapes rows into columns and does not append datasets.</span><span class='qd'><b>Filtering</b>: filtering removes rows by condition and does not combine files.</span>" },
{ id:"D2-067", domain:2, obj:"2.3", diff:"medium", q:"An analyst combines a customer table and a demographics table by matching customer_id, adding demographic columns to each customer row. This column-wise combination is best described as:", options:["Appending rows","Merging/joining on a key","Binning","Imputation"], answer:1, explain:"<strong>Merging/joining on a key</strong> adds columns from one dataset to another by matching a shared key, enriching each customer row with demographics.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Appending rows</b>: appending stacks rows vertically and does not add new columns by key.</span><span class='qd'><b>Binning</b>: binning groups numeric values and does not combine two tables.</span><span class='qd'><b>Imputation</b>: imputation fills missing values and does not merge datasets.</span>" },
{ id:"D2-068", domain:2, obj:"2.3", diff:"hard", q:"A JSON field stores an array of product tags in each row, like ['blue','sale','new']. The analyst needs one row per tag for analysis. Which transformation is required?", options:["Exploding (unnesting) the array into multiple rows","Concatenating the tags into one string","Binning the tags","Imputing missing tags"], answer:0, explain:"<strong>Exploding (unnesting) the array into multiple rows</strong> expands each array element into its own row, producing one row per tag for analysis.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Concatenating the tags into one string</b>: concatenation merges the tags into a single value, the opposite of separating them.</span><span class='qd'><b>Binning the tags</b>: binning groups numeric ranges and does not unnest an array.</span><span class='qd'><b>Imputing missing tags</b>: imputation fills missing values and does not split an existing array.</span>" },
{ id:"D2-069", domain:2, obj:"2.3", diff:"medium", q:"An analyst replaces missing categorical 'department' values with the most frequently occurring department. Which imputation method is this?", options:["Mean imputation","Mode imputation","Median imputation","Forward fill"], answer:1, explain:"<strong>Mode imputation</strong> fills missing categorical values with the most frequent category, which is appropriate because a mean cannot be computed for categories.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Mean imputation</b>: a mean requires numeric data and cannot be calculated for a department category.</span><span class='qd'><b>Median imputation</b>: a median also requires ordered numeric values, not nominal categories.</span><span class='qd'><b>Forward fill</b>: forward fill copies the prior row's value, which is a time-series technique, not frequency-based.</span>" },
{ id:"D2-070", domain:2, obj:"2.3", diff:"hard", q:"A time-series sensor log has occasional gaps. The analyst fills each gap with the last known reading before it. Which imputation technique is this?", options:["Forward fill (last observation carried forward)","Mean imputation","One-hot encoding","Listwise deletion"], answer:0, explain:"<strong>Forward fill (last observation carried forward)</strong> propagates the most recent prior value into the gap, a common approach for ordered time-series data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Mean imputation</b>: using the overall mean ignores the sequential nature of time-series readings.</span><span class='qd'><b>One-hot encoding</b>: one-hot encoding transforms categories and does not fill time gaps.</span><span class='qd'><b>Listwise deletion</b>: deleting the gapped timestamps would break the continuity of the series.</span>" },
{ id:"D2-071", domain:2, obj:"2.3", diff:"easy", q:"An analyst removes rows that are exact duplicates so each record appears only once. This cleansing step is:", options:["Concatenation","Scaling","Parsing","Deduplication"], answer:3, explain:"<strong>Deduplication</strong> removes repeated records so each unique entity is represented only once.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Concatenation</b>: concatenation joins strings and does not remove duplicate rows.</span><span class='qd'><b>Scaling</b>: scaling rescales numeric values and is unrelated to duplicates.</span><span class='qd'><b>Parsing</b>: parsing splits strings and does not eliminate repeated records.</span>" },
{ id:"D2-072", domain:2, obj:"2.3", diff:"medium", q:"A regex pattern '^\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\d{5}$' is applied to a 'zip' column. What does this pattern validate?", options:["A value that is exactly five digits","Any text containing the word zip","A value with at least one letter","A date in ISO format"], answer:0, explain:"<strong>A value that is exactly five digits</strong> — the anchors ^ and $ bound the whole string and \\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\d{5} requires precisely five digit characters, matching a US ZIP code.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Any text containing the word zip</b>: the pattern matches digit characters, not the literal word zip.</span><span class='qd'><b>A value with at least one letter</b>: \\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\d matches digits, and letters would fail the pattern.</span><span class='qd'><b>A date in ISO format</b>: an ISO date contains dashes and more than five digits, which this pattern rejects.</span>" },
{ id:"D2-073", domain:2, obj:"2.3", diff:"hard", q:"An analyst must replace every occurrence of the dash and parentheses in phone strings like '(555) 123-4567' to produce '5551234567'. Which approach is MOST efficient?", options:["Mean imputation","A find-and-replace using a regex character class","Binning the numbers","A LEFT OUTER JOIN"], answer:1, explain:"<strong>A find-and-replace using a regex character class</strong> can match all non-digit characters in one pass and strip them, leaving only the digits.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Mean imputation</b>: imputation fills missing values and cannot remove characters.</span><span class='qd'><b>Binning the numbers</b>: binning groups numeric ranges and does not clean string formatting.</span><span class='qd'><b>A LEFT OUTER JOIN</b>: a join combines tables and is unrelated to stripping characters from text.</span>" },
{ id:"D2-074", domain:2, obj:"2.3", diff:"medium", q:"A 'temperature_f' column must be converted to Celsius for an international report. Creating a new column with (F - 32) * 5/9 is an example of:", options:["Deduplication","A derived/calculated field via unit conversion","One-hot encoding","Listwise deletion"], answer:1, explain:"<strong>A derived/calculated field via unit conversion</strong> — applying the formula to each Fahrenheit value produces a new computed Celsius column.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deduplication</b>: deduplication removes duplicate rows and does not compute a new measure.</span><span class='qd'><b>One-hot encoding</b>: one-hot encoding transforms categories, not numeric unit conversions.</span><span class='qd'><b>Listwise deletion</b>: listwise deletion drops rows and does not convert units.</span>" },
{ id:"D2-075", domain:2, obj:"2.3", diff:"hard", q:"An analyst applies log transformation to a heavily right-skewed 'income' feature before modeling. What is the primary purpose of this transformation?", options:["To remove duplicate incomes","To encrypt the income values","To compress large values and reduce skewness so the distribution is more symmetric","To split income into two columns"], answer:2, explain:"<strong>To compress large values and reduce skewness so the distribution is more symmetric</strong> — a log transform pulls in the long right tail, helping models that assume more balanced distributions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To remove duplicate incomes</b>: a log transform changes scale, not the presence of duplicates.</span><span class='qd'><b>To encrypt the income values</b>: a log is reversible and is not an encryption technique.</span><span class='qd'><b>To split income into two columns</b>: a log transform produces one transformed value per row, not two columns.</span>" },
{ id:"D2-076", domain:2, obj:"2.3", diff:"medium", q:"An analyst standardizes inconsistent gender entries 'M', 'Male', and 'male' into a single value 'Male' using a mapping table. This is BEST described as:", options:["Imputation of missing values","Binning numeric ranges","Appending rows","Value standardization via lookup mapping"], answer:3, explain:"<strong>Value standardization via lookup mapping</strong> uses a reference table to convert variant entries into one canonical value, unifying the gender representations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Imputation of missing values</b>: imputation fills blanks, but here the values are present and merely inconsistent.</span><span class='qd'><b>Binning numeric ranges</b>: binning applies to continuous numbers, not categorical text normalization.</span><span class='qd'><b>Appending rows</b>: appending stacks datasets and does not standardize values within a column.</span>" },
{ id:"D2-077", domain:2, obj:"2.3", diff:"easy", q:"Replacing the abbreviation 'St.' with 'Street' throughout an address column is an example of which operation?", options:["Aggregation","Sampling","String find-and-replace","Indexing"], answer:2, explain:"<strong>String find-and-replace</strong> locates a substring and substitutes another, here expanding 'St.' to 'Street'.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Aggregation</b>: aggregation summarizes numeric data and does not edit text.</span><span class='qd'><b>Sampling</b>: sampling selects a subset of rows and does not modify values.</span><span class='qd'><b>Indexing</b>: indexing speeds lookups and does not replace text.</span>" },
{ id:"D2-078", domain:2, obj:"2.3", diff:"hard", q:"After merging two datasets on customer_id, the result has columns 'state_x' and 'state_y' that frequently disagree. What cleansing decision must the analyst make?", options:["Append both columns as new rows","Delete the customer_id key","Apply min-max scaling to the state names","Resolve the conflict by choosing an authoritative source or rule for the merged value"], answer:3, explain:"<strong>Resolve the conflict by choosing an authoritative source or rule for the merged value</strong> — conflicting merged columns require a survivorship rule to pick the correct, single value.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Append both columns as new rows</b>: appending rows does not reconcile two conflicting column values.</span><span class='qd'><b>Delete the customer_id key</b>: removing the join key would break the merge entirely.</span><span class='qd'><b>Apply min-max scaling to the state names</b>: scaling applies to numbers and cannot resolve text conflicts.</span>" },
{ id:"D2-079", domain:2, obj:"2.3", diff:"easy", q:"An analyst converts a 'is_active' column stored as 'Yes'/'No' text into Boolean 1/0 values for analysis. This is an example of:", options:["Type conversion/encoding to Boolean","Binning","Outlier removal","Sampling"], answer:0, explain:"<strong>Type conversion/encoding to Boolean</strong> maps the text 'Yes'/'No' onto 1/0 Boolean values suitable for computation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Binning</b>: binning groups continuous numbers into ranges, not two text values into Booleans.</span><span class='qd'><b>Outlier removal</b>: outlier removal drops extreme values and is unrelated to encoding yes/no.</span><span class='qd'><b>Sampling</b>: sampling selects rows and does not convert data types.</span>" },
{ id:"D2-080", domain:2, obj:"2.3", diff:"hard", q:"A 'revenue' field arrives as '$1,234.56' text with a currency symbol and thousands separator. To make it numeric, which sequence of transformations is correct?", options:["Cast to number first, then strip the symbols","Bin the values, then cast","One-hot encode, then sum","Strip the currency symbol and commas, then cast the cleaned string to a numeric type"], answer:3, explain:"<strong>Strip the currency symbol and commas, then cast the cleaned string to a numeric type</strong> — non-numeric characters must be removed before the cast, otherwise the conversion fails.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Cast to number first, then strip the symbols</b>: casting before cleaning fails because '$1,234.56' is not a valid number.</span><span class='qd'><b>Bin the values, then cast</b>: binning requires numeric input and cannot run on the raw currency text.</span><span class='qd'><b>One-hot encode, then sum</b>: one-hot encoding treats each amount as a category, which is nonsensical for a numeric measure.</span>" },
{ id:"D2-081", domain:2, obj:"2.1", diff:"medium", q:"An analyst needs counts of orders per customer but only for customers who have placed at least one order. Which join paired with grouping is appropriate?", options:["LEFT JOIN then COUNT all customers","CROSS JOIN then SUM","INNER JOIN customers to orders, then GROUP BY customer","UNION then DISTINCT"], answer:2, explain:"<strong>INNER JOIN customers to orders, then GROUP BY customer</strong> keeps only customers with matching orders and groups to count each customer's orders.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>LEFT JOIN then COUNT all customers</b>: a left join includes customers with zero orders, which the requirement excludes.</span><span class='qd'><b>CROSS JOIN then SUM</b>: a cross join pairs every customer with every order, producing meaningless counts.</span><span class='qd'><b>UNION then DISTINCT</b>: UNION stacks rows and cannot count orders per customer.</span>" },
{ id:"D2-082", domain:2, obj:"2.1", diff:"hard", q:"A nightly ETL pipeline transforms data in a separate staging server before loading the conformed result into the production warehouse. A key advantage of transforming before load in this design is:", options:["Only clean, conformed data lands in the production warehouse","The warehouse never stores any data","Transformation is impossible without ELT","The source system performs all computation"], answer:0, explain:"<strong>Only clean, conformed data lands in the production warehouse</strong> — staging-based ETL shields the warehouse from raw, messy data by validating and conforming it first.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The warehouse never stores any data</b>: the warehouse still stores the loaded conformed data; that is its purpose.</span><span class='qd'><b>Transformation is impossible without ELT</b>: ETL transforms data perfectly well before loading, so this is false.</span><span class='qd'><b>The source system performs all computation</b>: in this design a staging server, not the source, handles transformation.</span>" },
{ id:"D2-083", domain:2, obj:"2.1", diff:"medium", q:"A query filters a date column with 'WHERE order_date >= ''2024-01-01'' AND order_date < ''2025-01-01'''. Why is this often faster than 'WHERE YEAR(order_date) = 2024'?", options:["Functions on columns always run faster","The range form lets the engine use an index on order_date","The two forms return different rows","Indexes never help date columns"], answer:1, explain:"<strong>The range form lets the engine use an index on order_date</strong> — wrapping the column in YEAR() makes it non-sargable, preventing index seeks, whereas a plain range comparison can use the index.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Functions on columns always run faster</b>: applying a function to the indexed column usually disables the index and slows the query.</span><span class='qd'><b>The two forms return different rows</b>: both return all 2024 orders, so the results are equivalent.</span><span class='qd'><b>Indexes never help date columns</b>: indexes are very effective for range scans on date columns.</span>" },
{ id:"D2-084", domain:2, obj:"2.1", diff:"easy", q:"Which of the following BEST describes data acquisition?", options:["Designing a dashboard layout","Encrypting data backups","Writing the final report narrative","Gathering and importing data from sources into a usable environment"], answer:3, explain:"<strong>Gathering and importing data from sources into a usable environment</strong> defines data acquisition, the first step of preparing data for analysis.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Designing a dashboard layout</b>: dashboard design is a visualization task, not acquisition.</span><span class='qd'><b>Encrypting data backups</b>: encryption is a security control, not the gathering of data.</span><span class='qd'><b>Writing the final report narrative</b>: writing narrative is a reporting deliverable, not acquisition.</span>" },
{ id:"D2-085", domain:2, obj:"2.1", diff:"medium", q:"An analyst must pull data from a REST API that returns 100 records per page and paginates results. To acquire the full dataset, the acquisition routine must:", options:["Request page 1 only and assume it is complete","Convert the API to a CSV before any request","Use a CROSS JOIN on the endpoint","Loop through all pages until no more records are returned"], answer:3, explain:"<strong>Loop through all pages until no more records are returned</strong> — paginated APIs require iterating through successive pages to acquire every record.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Request page 1 only and assume it is complete</b>: stopping at page one captures just the first 100 records, missing the rest.</span><span class='qd'><b>Convert the API to a CSV before any request</b>: you cannot convert an API to a file without first requesting its data.</span><span class='qd'><b>Use a CROSS JOIN on the endpoint</b>: a cross join is a SQL operation and has no role in API pagination.</span>" },
{ id:"D2-086", domain:2, obj:"2.1", diff:"medium", q:"To reduce a 500-million-row table to a manageable analysis set, an analyst pulls a random 1% sample. The MAIN benefit of sampling here is:", options:["It guarantees zero outliers","It reduces processing cost while approximating the full population","It encrypts the data","It removes the need for any validation"], answer:1, explain:"<strong>It reduces processing cost while approximating the full population</strong> — a representative sample cuts compute and time while still supporting reliable estimates.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It guarantees zero outliers</b>: a random sample can and often does include outliers from the population.</span><span class='qd'><b>It encrypts the data</b>: sampling selects rows and provides no encryption.</span><span class='qd'><b>It removes the need for any validation</b>: sampled data still requires validation for quality.</span>" },
{ id:"D2-087", domain:2, obj:"2.2", diff:"medium", q:"An analyst computes the percentage of rows where every required field is populated and reports 88%. Which dimension of data quality does this metric express?", options:["Consistency","Accuracy","Completeness","Uniqueness"], answer:2, explain:"<strong>Completeness</strong> measures how fully required fields are populated, expressed here as the 88% of rows with no missing required values.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Consistency</b>: consistency measures whether the same value agrees across systems, not whether fields are filled.</span><span class='qd'><b>Accuracy</b>: accuracy measures whether values are correct, not merely present.</span><span class='qd'><b>Uniqueness</b>: uniqueness measures the absence of duplicates, not population of fields.</span>" },
{ id:"D2-088", domain:2, obj:"2.2", diff:"hard", q:"The same customer's birthdate is '1990-05-01' in the CRM but '1990-01-05' in billing. Both are populated and validly formatted. Which data quality dimension is violated?", options:["Consistency","Completeness","Uniqueness","Timeliness"], answer:0, explain:"<strong>Consistency</strong> is violated because the same fact has conflicting values across two systems, even though each value is present and well-formatted.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Completeness</b>: both records contain a birthdate, so nothing is missing.</span><span class='qd'><b>Uniqueness</b>: the issue is conflicting values, not duplicate records.</span><span class='qd'><b>Timeliness</b>: timeliness concerns how current data is, not whether two stored values agree.</span>" },
{ id:"D2-089", domain:2, obj:"2.2", diff:"easy", q:"An analyst opens a new dataset and first reviews each column's data type, min, max, and count of nulls. This initial overview is part of:", options:["Data exploration/profiling","Dashboard publishing","Encryption at rest","Report scheduling"], answer:0, explain:"<strong>Data exploration/profiling</strong> involves examining column types, ranges, and null counts to understand the dataset and surface quality issues.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Dashboard publishing</b>: publishing distributes a finished report, not an initial data review.</span><span class='qd'><b>Encryption at rest</b>: encryption secures stored data and is not a profiling step.</span><span class='qd'><b>Report scheduling</b>: scheduling automates report delivery and is unrelated to exploring a dataset.</span>" },
{ id:"D2-090", domain:2, obj:"2.2", diff:"medium", q:"A column should contain only the codes A, B, or C, but profiling reveals values of X and Z. Which validation rule would catch these?", options:["A duplicate check","A min-max scaling check","A concatenation check","A referential/domain (allowed-values) check"], answer:3, explain:"<strong>A referential/domain (allowed-values) check</strong> confirms each value belongs to the permitted set, flagging X and Z as invalid.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A duplicate check</b>: a duplicate check finds repeated rows, not values outside an allowed set.</span><span class='qd'><b>A min-max scaling check</b>: min-max scaling is a numeric transformation, not a validation rule.</span><span class='qd'><b>A concatenation check</b>: concatenation joins strings and is not a validation rule for allowed values.</span>" },
{ id:"D2-091", domain:2, obj:"2.2", diff:"hard", q:"A daily revenue column shows a steady range around 50,000 except for one day reading 4,200,000. Before treating it as an outlier, the analyst should FIRST check whether:", options:["The dataset is encrypted","The value reflects a real event such as a bulk order, or is a data-entry error","The column has an index","The table needs a UNION"], answer:1, explain:"<strong>The value reflects a real event such as a bulk order, or is a data-entry error</strong> — distinguishing a legitimate spike from a recording error determines whether to keep or correct the value.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The dataset is encrypted</b>: encryption status has no bearing on whether a value is a true outlier.</span><span class='qd'><b>The column has an index</b>: indexing affects performance, not the validity of a data point.</span><span class='qd'><b>The table needs a UNION</b>: a UNION combines result sets and is irrelevant to evaluating an outlier.</span>" },
{ id:"D2-092", domain:2, obj:"2.2", diff:"medium", q:"An analyst finds that 15% of records in a 'loyalty_tier' column are blank because those customers never enrolled. How should this missingness be interpreted?", options:["As corrupt data that must be deleted","As a duplicate","As legitimately not applicable, where blank meaningfully represents 'not enrolled'","As an outlier"], answer:2, explain:"<strong>As legitimately not applicable, where blank meaningfully represents 'not enrolled'</strong> — the absence carries real meaning and should not be blindly deleted or imputed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>As corrupt data that must be deleted</b>: the blanks are meaningful, so deleting them would lose valid information.</span><span class='qd'><b>As a duplicate</b>: a blank field is missing data, not a repeated record.</span><span class='qd'><b>As an outlier</b>: an outlier is an extreme present value, not a meaningful blank.</span>" },
{ id:"D2-093", domain:2, obj:"2.3", diff:"medium", q:"An analyst applies the same cleansing steps to a recurring feed by saving them as a reusable, repeatable workflow. The MAIN benefit of this approach is:", options:["It guarantees the source will never change","It encrypts the pipeline","It removes the need for validation forever","It ensures consistent, reproducible transformations on every load"], answer:3, explain:"<strong>It ensures consistent, reproducible transformations on every load</strong> — codifying the cleansing steps makes each run apply the identical logic, improving reliability and auditability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It guarantees the source will never change</b>: a workflow cannot control upstream source changes.</span><span class='qd'><b>It encrypts the pipeline</b>: a reusable workflow standardizes steps but provides no encryption.</span><span class='qd'><b>It removes the need for validation forever</b>: validation is still needed because source data can vary between loads.</span>" },
{ id:"D2-094", domain:2, obj:"2.3", diff:"hard", q:"An analyst must aggregate transaction amounts but the column mixes '1234.5', '1,234.50', and '1234.50 USD'. What is the correct cleansing approach before aggregation?", options:["Sum the strings directly","Parse and normalize each value to a consistent numeric type, removing separators and units","Bin the strings into ranges","Append the values as new rows"], answer:1, explain:"<strong>Parse and normalize each value to a consistent numeric type, removing separators and units</strong> — only after stripping commas and 'USD' and casting can the values be summed reliably.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Sum the strings directly</b>: summing inconsistent text strings fails or produces incorrect results.</span><span class='qd'><b>Bin the strings into ranges</b>: binning requires clean numeric input and does not aggregate amounts.</span><span class='qd'><b>Append the values as new rows</b>: appending stacks data and does not convert or total the amounts.</span>" },
{ id:"D2-095", domain:2, obj:"2.3", diff:"medium", q:"An analyst creates an 'order_month' column by extracting the month from an 'order_date' field. This new field is an example of:", options:["A derived field via date-part extraction","Deduplication","Outlier capping","Min-max scaling"], answer:0, explain:"<strong>A derived field via date-part extraction</strong> — pulling the month component from a date produces a new calculated column useful for grouping and trend analysis.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deduplication</b>: deduplication removes repeated rows and does not extract a date part.</span><span class='qd'><b>Outlier capping</b>: capping limits extreme values and is unrelated to extracting a month.</span><span class='qd'><b>Min-max scaling</b>: scaling rescales numbers and does not derive a month from a date.</span>" },
{ id:"D2-096", domain:2, obj:"2.3", diff:"hard", q:"An analyst caps all values above the 99th percentile at the 99th-percentile value to limit the influence of extreme highs without dropping rows. This technique is known as:", options:["Listwise deletion","Winsorizing (outlier capping)","One-hot encoding","Forward fill"], answer:1, explain:"<strong>Winsorizing (outlier capping)</strong> replaces extreme values with a chosen percentile boundary, reducing their leverage while retaining every row.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Listwise deletion</b>: deletion would drop the extreme rows rather than cap their values.</span><span class='qd'><b>One-hot encoding</b>: one-hot encoding transforms categories and does not cap numeric extremes.</span><span class='qd'><b>Forward fill</b>: forward fill imputes missing values and does not limit outliers.</span>" },
{ id:"D2-097", domain:2, obj:"2.3", diff:"medium", q:"An analyst replaces missing numeric values in a right-skewed 'home_price' column with the median rather than the mean. Why is the median preferred here?", options:["The median is always larger than the mean","The mean cannot be computed","The median is more robust to the skew and extreme values","Imputation requires the median by rule"], answer:2, explain:"<strong>The median is more robust to the skew and extreme values</strong> — in a skewed distribution the mean is pulled toward the tail, so the median better represents a typical value.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The median is always larger than the mean</b>: in a right-skewed distribution the median is typically smaller than the mean, not larger.</span><span class='qd'><b>The mean cannot be computed</b>: the mean can be computed; it is simply less representative under skew.</span><span class='qd'><b>Imputation requires the median by rule</b>: no rule forces the median; it is chosen for robustness here.</span>" },
{ id:"D2-098", domain:2, obj:"2.3", diff:"easy", q:"An analyst pads all product codes to a fixed length of 8 by adding leading zeros so '123' becomes '00000123'. This standardization technique is called:", options:["Binning","Imputation","Sampling","Zero-padding (string formatting)"], answer:3, explain:"<strong>Zero-padding (string formatting)</strong> prepends zeros to reach a fixed width, ensuring codes align consistently for matching and sorting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Binning</b>: binning groups numeric values into ranges and does not pad strings.</span><span class='qd'><b>Imputation</b>: imputation fills missing values and does not format existing codes.</span><span class='qd'><b>Sampling</b>: sampling selects rows and does not standardize code length.</span>" },
{ id:"D2-099", domain:2, obj:"2.3", diff:"hard", q:"After appending three regional files, an analyst notices region C used 'Y/N' while regions A and B used 'true/false' for an 'in_stock' flag. What must be done so the combined column is usable?", options:["Leave the values mixed","Delete region C entirely","Apply z-score normalization to the flags","Standardize all flag values to a single consistent representation"], answer:3, explain:"<strong>Standardize all flag values to a single consistent representation</strong> — the appended column must use one encoding (for example true/false) so filtering and aggregation behave correctly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Leave the values mixed</b>: mixed encodings break filters and counts on the combined column.</span><span class='qd'><b>Delete region C entirely</b>: dropping a region discards valid data that only needs reformatting.</span><span class='qd'><b>Apply z-score normalization to the flags</b>: z-scores apply to numeric data, not Boolean flag text.</span>" },
{ id:"D2-100", domain:2, obj:"2.3", diff:"medium", q:"An analyst must combine a small reference table of region names with a large fact table, adding the region name to each fact row by matching region_id. The correct preparation step is to:", options:["Append the reference rows beneath the fact table","Bin the region_id values","Merge (join) the reference table to the fact table on region_id","Impute the missing region names with the mean"], answer:2, explain:"<strong>Merge (join) the reference table to the fact table on region_id</strong> — a key-based join enriches every fact row with the matching region name from the lookup table.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Append the reference rows beneath the fact table</b>: appending stacks unrelated rows and does not attach the name to each fact row.</span><span class='qd'><b>Bin the region_id values</b>: binning groups numeric ranges and does not look up region names.</span><span class='qd'><b>Impute the missing region names with the mean</b>: a mean cannot be computed for text names, and the names are not missing but need joining.</span>" }
);
